class Solution:
    def createSortedArray(self, instructions):
        MOD = 10 ** 9 + 7
        max_val = max(instructions)
        bit = [0] * (max_val + 1)

        def update(pos):
            while pos <= max_val:
                bit[pos] += 1
                pos += pos & (-pos)

        def query(pos):
            s = 0
            while pos > 0:
                s += bit[pos]
                pos -= pos & (-pos)
            return s

        cost = 0
        for idx, v in enumerate(instructions):
            less = query(v - 1)
            leq = query(v)
            greater = idx - leq
            cost += min(less, greater)
            update(v)
        return cost % MOD

