var createSortedArray = function(instructions) {
    const MOD = 1000000007;
    let maxVal = 0;
    for (const v of instructions) if (v > maxVal) maxVal = v;
    const bit = new Array(maxVal + 1).fill(0);

    function update(pos) {
        while (pos <= maxVal) {
            bit[pos] += 1;
            pos += pos & (-pos);
        }
    }

    function query(pos) {
        let s = 0;
        while (pos > 0) {
            s += bit[pos];
            pos -= pos & (-pos);
        }
        return s;
    }

    let cost = 0;
    for (let idx = 0; idx < instructions.length; idx++) {
        const v = instructions[idx];
        const less = query(v - 1);
        const leq = query(v);
        const greater = idx - leq;
        cost += Math.min(less, greater);
        update(v);
    }
    return cost % MOD;
};
